var patBlockCharge = global.get("pat_block_charge") || false;
var config = global.get("fve_config") || {};
var status = global.get("fve_status") || {};
var minSoc = config.min_soc || 20;
var currentSoc = status.battery_soc || 50;
var cerpadloTopi = msg.cerpadloTopi || false;
var autoCharging = msg.autoNabijeniAktivni || false;
// v19.4: Read charger state directly — global may be stale after NR restart
var chargerEntity = global.get("homeassistant.homeAssistant.states['sensor.charger_state_garage']") || {};
if (chargerEntity.state === "2") autoCharging = true;
var saunaAktivni = msg.saunaAktivni || false;
var minDischargeBlokaceW = config.min_vybijeni_blokace_w || 1300;

// v19: Aktualni PV vykon pro rozhodovani o blokaci
var pvFveEntity = global.get("homeassistant.homeAssistant.states['sensor.vyroba_fve']") || {};
var currentPvPower = parseFloat(pvFveEntity.state) || 0;
var dynamicDischargeW = Math.max(0, Math.round(minDischargeBlokaceW - currentPvPower));
// v19.3: Proven pattern from ŠETŘIT — solar<=10W → MaxDischargePower=0
// Eliminates ~130W DC bus standby loss. Victron transfer relay handles grid passthrough.
var solarPassthrough = currentPvPower > 10 ? Math.max(50, Math.round(currentPvPower)) : 0;

// v19: Blokace vybijeni: POUZE pri nabijeni ze site, NIBE bez solaru, nebo saune
var gridChargingEntity = global.get("homeassistant.homeAssistant.states['input_boolean.nastavuj_amperaci_chargeru_grid']") || {};
var autoChargingFromGrid = autoCharging && (gridChargingEntity.state === "on");
var nibeFromGrid = cerpadloTopi;  // NIBE topí → vždy blokovat vybíjení baterie
// v19.4: Hard block discharge when car charges and SOC < threshold (battery priority)
var autoSocThreshold = config.nabijeni_auta_min_soc || 95;
var blockDischargeHard = autoCharging && currentSoc < autoSocThreshold;
var blockDischargeSoft = autoChargingFromGrid || nibeFromGrid || saunaAktivni;
var blockDischarge = blockDischargeHard || blockDischargeSoft;

msg.victron = {
    power_set_point: 0,
    min_soc: minSoc,
    schedule_soc: 0,
    schedule_charge_duration: 0,
    schedule_charge_day: -7,
    max_discharge_power: blockDischargeHard ? 0 : (blockDischargeSoft ? solarPassthrough : -1),
    max_charge_power: (patBlockCharge || blockDischargeSoft) ? 0 : -1,
    feedin_on: true,
    max_feed_in_power: 7600,
    prevent_feedback: 0
};
msg.mode = "normal";
msg.blockDischarge = blockDischarge;
msg.maxDischargePower = blockDischarge ? 0 : -1;
msg.maxChargePower = blockDischarge ? 0 : -1;

var consumers = [];
if (cerpadloTopi) consumers.push("Topeni");
if (autoCharging) consumers.push("Auto");
if (saunaAktivni) consumers.push("Sauna");
var consText = consumers.length > 0 ? " | " + consumers.join("+") : "";
var dischText = blockDischarge ? " | BLOK_DISCH:0W" : "";
node.status({fill: blockDischarge ? "yellow" : "green", shape:"dot", text:"NORMAL | SOC:" + currentSoc + "%" + consText + dischText});

global.set("energy_arbiter", {
    mode: "normal",
    battery_charging: false,
    battery_charge_rate_w: 0,
    power_set_point: 0,
    consumers_active: consumers,
    max_discharge_allowed: !blockDischarge,
    timestamp: Date.now()
});

return msg;

// === ŠETŘIT mód ===
// Baterie se NEVYBÍJÍ - max_discharge_power=0
// min_soc zůstává na hodnotě nastavené uživatelem
var patBlockCharge = global.get("pat_block_charge") || false;
var config = global.get("fve_config") || {};
var status = global.get("fve_status") || {};
var currentSoc = status.battery_soc || 50;
var minSoc = config.min_soc || 20;

// Přebytky solaru stále jdou do sítě (feed-in ON)
// Dynamic: MaxDischargePower = aktuální solar (DC bus passthrough)
var pvEntity = global.get("homeassistant.homeAssistant.states['sensor.vyroba_fve']") || {};
var rawSolar = Math.round(parseFloat(pvEntity.state) || 0);
// v19.3: Když solar=0 (noc), MaxDischargePower=0 blokuje DC bus standby loss
// Victron transfer relay zajistí grid passthrough i s MaxDischargePower=0
var currentSolar = rawSolar > 10 ? Math.max(50, rawSolar) : 0;

// v19.3: Grid bias kompenzuje inverter standby (~130W) aby baterie nevybijela
var gridBias = config.setrit_grid_bias_w || 150;
msg.victron = {
    power_set_point:           gridBias,
    min_soc:                   minSoc,
    schedule_soc:              0,
    schedule_charge_duration:  0,
    schedule_charge_day:       -7,
    max_discharge_power:       currentSolar,
    max_charge_power:          patBlockCharge ? 0 : -1,
    feedin_on:                 true,
    max_feed_in_power:         config.max_feed_in_w || 7600,
    prevent_feedback:          0
};
msg.mode = "setrit";
msg.blockDischarge = true;

node.status({fill:"yellow", shape:"dot", text:"SETRIT | SOC:" + currentSoc + "% | minSOC:" + minSoc + "% | PSP:" + gridBias + "W | max_disch:" + currentSolar});

global.set("energy_arbiter", {
    mode: "setrit",
    battery_charging: false,
    battery_charge_rate_w: 0,
    power_set_point: 0,
    consumers_active: [],
    max_discharge_allowed: false,
    timestamp: Date.now()
});

return msg;

var patBlockCharge = global.get("pat_block_charge") || false;
var config = global.get("fve_config") || {};
var minSoc = config.min_soc || 20;
var status = global.get("fve_status") || {};
var currentSoc = status.battery_soc || 50;
var maxGridW = config.max_spotreba_sit_w || 22000;
var SAFETY_MARGIN = config.safety_margin_w || 2000;
var cerpadloTopi = msg.cerpadloTopi || false;
var autoCharging = msg.autoNabijeniAktivni || false;
var saunaAktivni = msg.saunaAktivni || false;

var plan = global.get("fve_plan") || {};
// FIX: v manuálním režimu NABÍJET vždy targetSoc=100
var manualMod = (global.get("fve_config") || {}).manual_mod || "auto";
var targetSoc;
if (manualMod === "nabijet_ze_site") {
    targetSoc = 100;
} else {
    targetSoc = (plan && plan.smartCharging && plan.smartCharging.targetSocFromGrid > 0)
        ? plan.smartCharging.targetSocFromGrid : 100;
}

var consumers = [];
if (cerpadloTopi) consumers.push("Topeni");
if (autoCharging) consumers.push("Auto");
if (saunaAktivni) consumers.push("Sauna");

var psp, statusText;
if (cerpadloTopi || autoCharging) {
    var safeImport = maxGridW - SAFETY_MARGIN;
    psp = safeImport;
    statusText = "Nabijet+" + consumers.join("+") + " | PSP:" + safeImport + "W | SOC:" + currentSoc + "%";
} else {
    psp = -maxGridW;
    statusText = "Nabijet | SCHED:" + targetSoc + "% | PSP:" + psp + "W | SOC:" + currentSoc + "%";
}

msg.victron = {
    power_set_point: psp,
    min_soc: minSoc,
    schedule_soc: targetSoc,
    schedule_charge_duration: 86399,
    schedule_charge_day: 7,
    max_discharge_power: -1,
    max_charge_power: patBlockCharge ? 0 : -1,
    feedin_on: true,
    max_feed_in_power: 7600,
    prevent_feedback: 0
};
msg.mode = "nabijet_ze_site";

// Diagnostika: loguj co NABÍJET posílá do Victronu
node.warn("NABIJET: psp=" + psp + " sched_soc=" + targetSoc + " sched_day=7 sched_dur=86399 | SOC:" + currentSoc + "% | consumers:" + consumers.join(","));

node.status({fill:"blue", shape:"dot", text: statusText});

global.set("energy_arbiter", {
    mode: "nabijet_ze_site",
    battery_charging: true,
    battery_charge_rate_w: 5000,
    power_set_point: psp,
    consumers_active: consumers,
    max_discharge_allowed: false,
    timestamp: Date.now()
});

return msg;

var patBlockCharge = global.get("pat_block_charge") || false;
var saunaAktivni = msg.saunaAktivni || false;
var config = global.get("fve_config") || {};
var status = global.get("fve_status") || {};

if (msg.autoNabijeniAktivni) {
    node.status({fill:"yellow", shape:"ring", text:"Skip prodej - auto se nabíjí"});
    return null;
}

var currentSoc = status.battery_soc || 50;
var minSoc = config.min_soc || 20;
var maxFeedIn = config.max_feed_in_w || 7600;

if (currentSoc <= minSoc + 1) {
    node.status({fill:"red", shape:"ring", text:"Nedostatek energie"});
    return null;
}

var effectiveMinSoc = Math.max(minSoc, currentSoc - 1);

msg.victron = {
    power_set_point: 0,
    min_soc: effectiveMinSoc,
    schedule_soc: 0,
    schedule_charge_duration: 0,
    schedule_charge_day: -7,
    max_discharge_power: -1,
    max_charge_power: patBlockCharge ? 0 : -1,
    feedin_on: true,
    max_feed_in_power: 7600,
    prevent_feedback: 0
};
msg.mode = "prodavat";
msg.feedInExcess = true;
node.status({fill:"red", shape:"dot", text:"Prodávat (solar) | SOC: " + currentSoc + "% (min:" + effectiveMinSoc + "%)"});

var consumers = [];
if (msg.cerpadloTopi) consumers.push("Topeni");
if (msg.saunaAktivni) consumers.push("Sauna");
if (msg.autoNabijeniAktivni) consumers.push("Auto");

global.set("energy_arbiter", {
    mode: "prodavat",
    battery_charging: false,
    reserved_for_battery_w: 0,
    max_discharge_allowed: true,
    consumers_active: consumers,
    timestamp: Date.now()
});

return msg;

var patBlockCharge = global.get("pat_block_charge") || false;
var saunaAktivni = msg.saunaAktivni || false;
var config = global.get("fve_config") || {};
var status = global.get("fve_status") || {};
var currentSoc = status.battery_soc || 50;
var minSoc = config.min_soc || 20;

// === ULTRA LEVNA DETEKCE ===
var prices = global.get("fve_prices_forecast") || [];
var hour = new Date().getHours();
var plan = global.get("fve_plan") || {};
var solarStart = (plan && plan.solarStartHour) || 9;
var solarEnd = (plan && plan.solarEndHour) || 17;
var isSolarHour = (hour >= solarStart && hour < solarEnd);
var PRAH_ULTRA_LEVNA = config.prah_ultra_levna_nakup || 1.0;

var currentBuyPrice = 99;
for (var i = 0; i < prices.length; i++) {
    if (prices[i].hour === hour && (prices[i].minute === 0 || prices[i].minute === undefined)) {
        currentBuyPrice = parseFloat(prices[i].priceCZKhourBuy) || 99;
        break;
    }
}

var ultraLevna = isSolarHour && currentBuyPrice < PRAH_ULTRA_LEVNA;
global.set("ultra_levna_energie", ultraLevna);

msg.victron = {
    power_set_point: 100,
    min_soc: minSoc,
    schedule_soc: 0,
    schedule_charge_duration: 0,
    schedule_charge_day: -7,
    max_discharge_power: -1,
    max_charge_power: patBlockCharge ? 0 : -1,
    feedin_on: false,
    max_feed_in_power: 0,
    prevent_feedback: 1
};
msg.mode = "zakaz_pretoku";
var autoText = msg.autoNabijeniAktivni ? " + Auto" : "";

if (ultraLevna) {
    node.status({fill:"yellow", shape:"dot", text:"ULTRA LEVNA " + currentBuyPrice.toFixed(2) + " Kc" + autoText + " | SOC " + currentSoc + "%"});
} else {
    node.status({fill:"purple", shape:"dot", text:"Zakaz pretoku" + autoText + " | SOC " + currentSoc + "%"});
}

var consumers = [];
if (msg.cerpadloTopi) consumers.push("Topeni");
if (msg.saunaAktivni) consumers.push("Sauna");
if (msg.autoNabijeniAktivni) consumers.push("Auto");
if (ultraLevna) consumers.push("UltraLevna");

global.set("energy_arbiter", {
    mode: ultraLevna ? "ultra_levna" : "zakaz_pretoku",
    battery_charging: false,
    max_discharge_allowed: true,
    consumers_active: consumers,
    timestamp: Date.now()
});

return msg;

var patBlockCharge = global.get("pat_block_charge") || false;
var config = global.get("fve_config") || {};
var status = global.get("fve_status") || {};
var minSoc = config.min_soc || 20;
var currentSoc = status.battery_soc || 50;
var cerpadloTopi = msg.cerpadloTopi || false;
var autoCharging = msg.autoNabijeniAktivni || false;
var saunaAktivni = msg.saunaAktivni || false;
var minDischargeBlokaceW = config.min_vybijeni_blokace_w || 1300;

var pvFveEntity = global.get("homeassistant.homeAssistant.states['sensor.vyroba_fve']") || {};
var currentPvPower = parseFloat(pvFveEntity.state) || 0;
var dynamicDischargeW = Math.max(0, Math.round(minDischargeBlokaceW - currentPvPower));

var nibeFromGrid = cerpadloTopi && currentPvPower < 500;
var blockDischarge = nibeFromGrid || saunaAktivni;

msg.victron = {
    power_set_point: 0,
    min_soc: minSoc,
    schedule_soc: 0,
    schedule_charge_duration: 0,
    schedule_charge_day: -7,
    // v19.3: Proven pattern — solar<=10W → 0 (eliminates DC bus standby loss)
    max_discharge_power: blockDischarge ? (currentPvPower > 10 ? Math.max(50, Math.round(currentPvPower)) : 0) : -1,
    max_charge_power: patBlockCharge ? 0 : -1,
    feedin_on: true,
    max_feed_in_power: 7600,
    prevent_feedback: 0
};
msg.mode = "solar_charging";
msg.blockDischarge = blockDischarge;
msg.maxDischargePower = -1;

var consumers = [];
if (cerpadloTopi) consumers.push(nibeFromGrid ? "NIBE(sit)" : "NIBE(sol)");
if (autoCharging) consumers.push("Auto(sol)");
if (saunaAktivni) consumers.push("Sauna");
var consText = consumers.length > 0 ? " | " + consumers.join("+") : "";

node.status({
    fill: "yellow",
    shape: "ring",
    text: "Solární" + consText + " | SOC: " + currentSoc + "%" + (blockDischarge ? " (BAT LOCKED)" : "")
});

global.set("energy_arbiter", {
    mode: "solar_charging",
    battery_charging: !blockDischarge,
    battery_discharging: !blockDischarge,
    reserved_for_battery_w: 0,
    max_discharge_allowed: !blockDischarge,
    consumers_active: consumers,
    timestamp: Date.now()
});

return msg;

// Fan-out: přečte msg.victron a nastaví msg properties pro Mustache templates
var v = msg.victron || {};
msg.victron = v;

// DIAG: loguj co fan-out posílá do Victronu

// Feed-in control
msg.feedin_on = (v.feedin_on !== false);
msg.feedin_max = (v.max_feed_in_power !== undefined) ? v.max_feed_in_power : 7600;
msg.prevent_feedback = v.prevent_feedback || 0;

return msg;

// FVE Logger - pripravi log radek
var arbiter = global.get("energy_arbiter") || {};
var config  = global.get("fve_config") || {};
var status  = global.get("fve_status") || {};
var pvState  = global.get("homeassistant.homeAssistant.states['sensor.fve_dostupny_prebytek']") || {};
var nibeState = global.get("homeassistant.homeAssistant.states['switch.nibe_topeni']") || {};

var entry = {
    ts: new Date().toISOString(),
    mode: msg.mode || arbiter.mode || "?",
    soc: status.battery_soc || 0,
    prebytek_w: parseFloat(pvState.state) || 0,
    block_discharge: msg.blockDischarge || false,
    block_min_soc: config.min_soc || 20,
    nibe: nibeState.state || "?",
    topeni_mod: global.get("topeni_mod") || "?",
    consumers: (arbiter.consumers_active || []).join("+") || "-"
};

msg.payload = JSON.stringify(entry);
return msg;

// FVE Logger - rotace souboru (odstran zaznamy starsi 3 dny)
var fs = require('fs');
var logFile = "/homeassistant/fve_log.jsonl";
var cutoff = new Date(Date.now() - 3 * 24 * 60 * 60 * 1000).toISOString();

try {
    var existing = "";
    try { existing = fs.readFileSync(logFile, "utf8"); } catch(e) {}
    var lines = existing.split("\n").filter(function(l) {
        if (!l.trim()) return false;
        try { return JSON.parse(l).ts >= cutoff; } catch(e) { return false; }
    });
    if (lines.length > 0) {
        fs.writeFileSync(logFile, lines.join("\n") + "\n", "utf8");
        node.status({fill:"green", shape:"dot", text: lines.length + " radku zachovano"});
    }
} catch(e) {
    node.warn("Rotace log error: " + e.message);
}
return null;
